class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        count_s = {}
        count_t = {}
        for char in s:
            if char in count_s:
                count_s[char] += 1
            else:
                count_s[char] = 1
        for char in t:
            if char in count_t:
                count_t[char] += 1
            else:
                count_t[char] = 1
        res = 0
        for key in count_s:
            if key in count_t:
                res += min(count_s[key], count_t[key])
        return res * 2 + (1 if res % 2 == 0 else 0)
